### Swift Do-Catch and Try

The `do-catch` statement handles errors thrown by functions. Combined with `try`, `try?`, and `try!`, it provides flexible error handling patterns.

**Do-Catch Syntax:**

```swift
do {
    let result = try throwingFunction()
    // Use result
} catch pattern1 {
    // Handle specific error
} catch pattern2 where condition {
    // Handle with condition
} catch {
    // Catch-all handler
}
```

**Catching Specific Errors:**

```swift
enum MathError: Error {
    case divisionByZero
    case negativeSquareRoot
    case outOfRange(value: Int)
}

func safeDivide(_ a: Int, by b: Int) throws -> Int {
    guard b != 0 else { throw MathError.divisionByZero }
    return a / b
}

do {
    let result = try safeDivide(10, by: 0)
    print("Result: \(result)")
} catch MathError.divisionByZero {
    print("Cannot divide by zero!")
} catch {
    print("Other error: \(error)")
}
```

**Try Variants:**

| Variant | Behavior | When to Use |
|---------|----------|-------------|
| `try` | Must be in do-catch or throwing function | Normal handling |
| `try?` | Returns nil on error | Ignore error details |
| `try!` | Crashes on error | Guaranteed no error |

```swift
// try? - convert error to optional
let optionalResult = try? safeDivide(10, by: 2)
print(optionalResult ?? 0)  // 5

let failedResult = try? safeDivide(10, by: 0)
print(failedResult ?? 0)  // 0 (nil returned, no crash)

// try! - force unwrap (use only when certain)
let guaranteedResult = try! safeDivide(10, by: 2)
print(guaranteedResult)  // 5
```

**Catching Multiple Error Types:**

```swift
do {
    let data = try loadData()
    let parsed = try parse(data)
    try save(parsed)
} catch is NetworkError {
    print("Network issue")
} catch let error as FileError {
    print("File problem: \(error)")
} catch let error where error.localizedDescription.contains("timeout") {
    print("Operation timed out")
} catch {
    print("Unknown: \(error)")
}
```

**Cleanup with Defer:**

```swift
func processFile() throws {
    let file = open()
    defer { close(file) }  // Always executes on exit

    try write(file, data: "Hello")
    try process(file)
    // defer runs here even if above throws
}
```

> **Key Point:** Use `try?` when you don't care about the specific error. Use `try!` only when you are absolutely certain the operation won't fail (e.g., loading bundled resources).

Defer statements execute in reverse order of declaration when the current scope is exited, regardless of how the scope exits (success, error, or return).

codeExample:
import Foundation

enum FileSystemError: Error {
    case fileNotFound(path: String)
    case permissionDenied
    case diskFull(spaceRequired: Int)
}

func readConfiguration(path: String) throws -> String {
    guard path.hasSuffix(".json") else {
        throw FileSystemError.fileNotFound(path: path)
    }
    return "{\"setting\": \"value\"}"
}

// Multiple catch patterns
func loadConfig(from path: String) {
    do {
        let content = try readConfiguration(path: path)
        print("Loaded config: \(content)")
    } catch FileSystemError.fileNotFound(let path) {
        print("Config file not found at \(path)")
    } catch FileSystemError.permissionDenied {
        print("Permission denied")
    } catch FileSystemError.diskFull(let required) {
        print("Need \(required)MB free space")
    } catch {
        print("Unknown error: \(error)")
    }
}

// try? usage
if let config = try? readConfiguration(path: "settings.json") {
    print("Config: \(config)")
} else {
    print("Could not load config")
}

loadConfig(from: "config.json")
loadConfig(from: "data.txt")
